"use client"

import { type ComponentType, useEffect, useRef } from "react"
import { cn } from "./lib"
import { rgb, type Rgb } from "./palette"
import {
  BAYER4,
  clamp01,
  fillOf,
  type PixelBloom,
  type PixelColor,
  pixelBloomStyle,
  pixelPrefersReducedMotion,
} from "./pixel"

export type DitherIconProps = {
  /** The SVG icon component to compile (e.g. any lucide-react icon). */
  icon: ComponentType<{ strokeWidth?: number }>
  color?: PixelColor
  /** Square size in px. */
  size?: number
  /** CSS px per dither cell — 1 is crisp, 2+ reads chunkier/pixel-art. */
  cell?: number
  /** Stroke width passed to the source icon — thicken for coarse cells. */
  strokeWidth?: number
  /** Glow on the dither fill. */
  bloom?: PixelBloom
  /** Play the Bayer-ordered materialize entrance. */
  animate?: boolean
  animationDuration?: number
  /** Controlled reveal (0–1), e.g. scroll-linked. Overrides `animate`. */
  progress?: number
  /** Bump to replay the entrance. */
  replayToken?: number
  /** Descriptive label, or null for decorative (aria-hidden). */
  ariaLabel?: string | null
  className?: string
}

/** Sampled alpha (0–255) → cell dither density. Below the floor the cell is
 * off; above it density spans ~0.37–0.85, so even solid fills keep the
 * texture (a density of 1 would paint every cell and lose the dither). */
export function alphaToDensity(alpha: number): number {
  if (alpha < 24) return 0
  return 0.35 + 0.5 * (alpha / 255)
}

type IconModel = {
  density: number[] // cols×rows, row-major
  cols: number
  rows: number
}

/**
 * Rasterize the icon's `<svg>` at cell resolution and read the alpha channel
 * — the "compile" step. Colours don't matter (only coverage does), so
 * currentColor is pinned to an opaque ink before serializing.
 */
function sampleSvg(
  svg: SVGElement,
  cols: number,
  rows: number,
  onModel: (model: IconModel) => void
): () => void {
  const clone = svg.cloneNode(true) as SVGElement
  clone.setAttribute("xmlns", "http://www.w3.org/2000/svg")
  const markup = new XMLSerializer()
    .serializeToString(clone)
    .replaceAll("currentColor", "#fff")

  let cancelled = false
  const img = new Image()
  img.onload = () => {
    if (cancelled) return
    const sampler = document.createElement("canvas")
    sampler.width = cols
    sampler.height = rows
    const sctx = sampler.getContext("2d", { willReadFrequently: true })
    if (!sctx) return
    sctx.drawImage(img, 0, 0, cols, rows)
    const data = sctx.getImageData(0, 0, cols, rows).data
    const density = new Array<number>(cols * rows)
    for (let i = 0; i < cols * rows; i++) {
      density[i] = alphaToDensity(data[i * 4 + 3])
    }
    onModel({ density, cols, rows })
  }
  img.src = `data:image/svg+xml;charset=utf-8,${encodeURIComponent(markup)}`
  return () => {
    cancelled = true
  }
}

/** Size the backing stores once per compiled model — resizing resets the
 * canvas, so the per-frame painter must never touch width/height. */
function sizeIconCanvases(
  canvas: HTMLCanvasElement,
  bloomCanvas: HTMLCanvasElement | null,
  model: IconModel
): void {
  canvas.width = model.cols
  canvas.height = model.rows
  if (bloomCanvas) {
    bloomCanvas.width = model.cols
    bloomCanvas.height = model.rows
  }
}

/** Paint one frame at reveal `progress`, cells materializing in Bayer order
 * (same entrance as the avatar/charts). */
function paintIcon(
  canvas: HTMLCanvasElement,
  bloomCanvas: HTMLCanvasElement | null,
  model: IconModel,
  fill: Rgb,
  progress: number
): void {
  const ctx = canvas.getContext("2d")
  if (!ctx) return
  const { density, cols, rows } = model
  ctx.clearRect(0, 0, cols, rows)
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      const d = density[r * cols + c]
      if (d <= 0) continue
      const start = BAYER4[r % 4][c % 4] * 0.7
      const cellAlpha = clamp01((progress - start) / 0.3)
      if (cellAlpha <= 0) continue
      const lit = d > BAYER4[r & 3][c & 3]
      const alpha = (lit ? 0.35 + 0.65 * d : 0.12 * d) * cellAlpha
      ctx.fillStyle = rgb(fill, 1, alpha)
      ctx.fillRect(c, r, 1, 1)
    }
  }
  const bloomCtx = bloomCanvas?.getContext("2d") ?? null
  if (bloomCanvas && bloomCtx) {
    bloomCtx.clearRect(0, 0, cols, rows)
    bloomCtx.drawImage(canvas, 0, 0)
  }
}

/**
 * SVG→dither compiler — takes any SVG icon component, rasterizes it at cell
 * resolution, and re-emits it through the ordered-dither texture the rest of
 * the kit is made of. Reveals with the Bayer materialize entrance, or under
 * a controlled `progress` for scroll-linked reveals.
 */
export function DitherIcon({
  icon: Icon,
  color = "grey",
  size = 24,
  cell = 1,
  strokeWidth = 2,
  bloom = "off",
  animate = true,
  animationDuration = 500,
  progress,
  replayToken = 0,
  ariaLabel = null,
  className,
}: DitherIconProps) {
  const holderRef = useRef<HTMLSpanElement>(null)
  const canvasRef = useRef<HTMLCanvasElement>(null)
  const bloomRef = useRef<HTMLCanvasElement>(null)
  const modelRef = useRef<IconModel | null>(null)
  // The sampling effect must not re-run when only `progress` scrubs — read it
  // through a ref there instead of listing it as a dep.
  const progressRef = useRef(progress)
  progressRef.current = progress

  // Compile: sample the hidden SVG, then reveal (entrance loop, controlled
  // progress, or a single full paint).
  useEffect(() => {
    const holder = holderRef.current
    const canvas = canvasRef.current
    const svg = holder?.querySelector("svg")
    if (!holder || !canvas || !svg) return

    const fill = fillOf(color)
    const cells = Math.max(4, Math.round(size / cell))
    let raf = 0
    const cancelSample = sampleSvg(svg, cells, cells, (model) => {
      modelRef.current = model
      sizeIconCanvases(canvas, bloomRef.current, model)
      const controlled = progressRef.current
      if (controlled != null) {
        paintIcon(canvas, bloomRef.current, model, fill, clamp01(controlled))
        return
      }
      if (!animate || pixelPrefersReducedMotion()) {
        paintIcon(canvas, bloomRef.current, model, fill, 1)
        return
      }
      const start = performance.now()
      const tick = (now: number) => {
        // A controlled `progress` arriving mid-entrance takes over — stop the
        // loop instead of overpainting the host's frame.
        if (progressRef.current != null) return
        const t = clamp01((now - start) / animationDuration)
        paintIcon(canvas, bloomRef.current, model, fill, 1 - (1 - t) ** 3)
        if (t < 1) raf = requestAnimationFrame(tick)
      }
      raf = requestAnimationFrame(tick)
    })

    return () => {
      cancelSample()
      if (raf) cancelAnimationFrame(raf)
    }
  }, [Icon, color, size, cell, strokeWidth, bloom, animate, animationDuration, replayToken])

  // Controlled scrub: repaint on progress once the model is compiled.
  useEffect(() => {
    const canvas = canvasRef.current
    const model = modelRef.current
    if (progress == null || !canvas || !model) return
    paintIcon(canvas, bloomRef.current, model, fillOf(color), clamp01(progress))
  }, [progress, color])

  const bloomStyle = pixelBloomStyle(bloom)

  return (
    <span
      role={ariaLabel == null ? undefined : "img"}
      aria-label={ariaLabel ?? undefined}
      aria-hidden={ariaLabel == null || undefined}
      className={cn("relative inline-block align-middle", className)}
      style={{ width: size, height: size }}
    >
      {/* Hidden source SVG — the thing we compile. */}
      <span
        ref={holderRef}
        aria-hidden
        className="pointer-events-none absolute h-0 w-0 overflow-hidden opacity-0"
      >
        <Icon strokeWidth={strokeWidth} />
      </span>
      <canvas
        ref={canvasRef}
        className="absolute inset-0 h-full w-full"
        style={{ imageRendering: "pixelated" }}
      />
      {bloomStyle && (
        <canvas
          ref={bloomRef}
          className="pointer-events-none absolute inset-0 h-full w-full"
          style={bloomStyle}
        />
      )}
    </span>
  )
}

// Standalone pixel primitives for the non-chart Dither Kit pieces (avatar,
// gradient). Deliberately free of the chart engine so those items install
// without `core` — only palette.ts is shared. The Bayer matrix and bloom
// presets mirror dither-paint.ts so everything reads as one texture.

import { type DitherColor, PALETTE, type Rgb } from "./palette"

// 4×4 ordered (Bayer) matrix, normalized to 0–1 thresholds — the same matrix
// the charts dither with.
export const BAYER4 = [
  [0, 8, 2, 10],
  [12, 4, 14, 6],
  [3, 11, 1, 9],
  [15, 7, 13, 5],
].map((row) => row.map((v) => (v + 0.5) / 16))

export const clamp01 = (t: number) => (t < 0 ? 0 : t > 1 ? 1 : t)

/** 32-bit FNV-1a hash — turns any string seed into a stable uint32. */
export function fnv1a(str: string): number {
  let h = 0x811c9dc5
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i)
    h = Math.imul(h, 0x01000193)
  }
  return h >>> 0
}

/** Tiny deterministic PRNG (xorshift32) — returns floats in [0, 1). */
export function xorshift32(seed: number): () => number {
  let s = seed || 0x9e3779b9
  return () => {
    s ^= s << 13
    s >>>= 0
    s ^= s >>> 17
    s ^= s << 5
    s >>>= 0
    return s / 0x100000000
  }
}

/** A named palette colour or a raw hue (0–360). */
export type PixelColor = DitherColor | number

/** Hue (0–360) → an rgb fill tuned to sit alongside the chart palette. */
export function hueFill(hue: number): Rgb {
  const h = ((hue % 360) + 360) % 360
  const s = 0.85
  const l = 0.58
  const c = (1 - Math.abs(2 * l - 1)) * s
  const x = c * (1 - Math.abs(((h / 60) % 2) - 1))
  const m = l - c / 2
  const [r, g, b] =
    h < 60
      ? [c, x, 0]
      : h < 120
        ? [x, c, 0]
        : h < 180
          ? [0, c, x]
          : h < 240
            ? [0, x, c]
            : h < 300
              ? [x, 0, c]
              : [c, 0, x]
  return [
    Math.round((r + m) * 255),
    Math.round((g + m) * 255),
    Math.round((b + m) * 255),
  ]
}

/** Resolve a {@link PixelColor} to its rgb fill. */
export function fillOf(color: PixelColor): Rgb {
  return typeof color === "number" ? hueFill(color) : PALETTE[color].fill
}

// Bloom — same recipe as the charts: a blurred copy of the crisp canvas,
// composited additively so the glow stays in the dither's own colour.
export type PixelBloom = "off" | "low" | "high" | "aura"

const BLOOM_PRESET: Record<
  Exclude<PixelBloom, "off">,
  { blur: number; brightness: number; opacity: number; saturate: number }
> = {
  low: { blur: 3, brightness: 1.35, opacity: 0.7, saturate: 1.4 },
  high: { blur: 5, brightness: 1.5, opacity: 0.78, saturate: 1.5 },
  aura: { blur: 15, brightness: 2.9, opacity: 0.1, saturate: 3 },
}

export type PixelBloomStyle = {
  filter: string
  opacity: number
  mixBlendMode: "plus-lighter"
  imageRendering: "auto"
}

/** Style for the bloom layer canvas. null when off. */
export function pixelBloomStyle(bloom: PixelBloom): PixelBloomStyle | null {
  if (bloom === "off") return null
  const cfg = BLOOM_PRESET[bloom]
  return {
    filter: `blur(${cfg.blur}px) brightness(${cfg.brightness}) saturate(${cfg.saturate})`,
    opacity: cfg.opacity,
    mixBlendMode: "plus-lighter",
    imageRendering: "auto",
  }
}

/** Whether the OS asks for reduced motion (skip entrances). */
export function pixelPrefersReducedMotion(): boolean {
  return (
    window.matchMedia?.("(prefers-reduced-motion: reduce)")?.matches ?? false
  )
}

// Shared seed palette for the dither chart family. Mirrors the seeds in
// `dither-chart.tsx` so a series rendered through the composable engine reads
// with the exact same fill / line / star hues as the legacy sparkline.

export type Rgb = [number, number, number]

export type DitherColor =
  | "green"
  | "blue"
  | "purple"
  | "pink"
  | "orange"
  | "red"
  | "grey"

export type Seed = { fill: Rgb; line: Rgb; star: Rgb }

// Each seed: the area-fill hue, the bright series line, and the star sparkle.
export const PALETTE: Record<DitherColor, Seed> = {
  green: { fill: [40, 210, 110], line: [150, 255, 180], star: [200, 255, 220] },
  blue: { fill: [53, 143, 243], line: [150, 200, 255], star: [205, 228, 255] },
  purple: {
    fill: [150, 110, 255],
    line: [200, 175, 255],
    star: [225, 210, 255],
  },
  pink: { fill: [240, 90, 190], line: [255, 170, 220], star: [255, 205, 235] },
  orange: {
    fill: [255, 150, 50],
    line: [255, 195, 130],
    star: [255, 220, 175],
  },
  red: { fill: [240, 70, 70], line: [255, 150, 140], star: [255, 195, 185] },
  // No-data: a muted grey so empty metrics read as "nothing here".
  grey: { fill: [92, 92, 100], line: [140, 140, 150], star: [165, 165, 175] },
}

export const rgb = ([r, g, b]: Rgb, k = 1, a = 1) =>
  `rgba(${Math.round(r * k)},${Math.round(g * k)},${Math.round(b * k)},${a})`

export const seedOfColor = (color: DitherColor): Seed => PALETTE[color]

export const isDitherColor = (value: unknown): value is DitherColor =>
  typeof value === "string" && value in PALETTE

import { type ClassValue, clsx } from "clsx"
import { twMerge } from "tailwind-merge"

/** Tailwind-aware className combiner — local copy so the chart pack is
 * self-contained and portable as a registry. */
export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}
